124   void replaceValue(Value &Old, Value &New) {
125     Old.replaceAllUsesWith(&New);
126     if (auto *NewI = dyn_cast<Instruction>(&New)) {
127       New.takeName(&Old);
128       Worklist.pushUsersToWorkList(*NewI);
129       Worklist.pushValue(NewI);
130     }
131     Worklist.pushValue(&Old);
132   }
