2587 /// This is the entry point for all transforms. Pass manager differences are
2588 /// handled in the callers of this function.
2589 bool VectorCombine::run() {
2590   if (DisableVectorCombine)
2591     return false;
2592 
2593   // Don't attempt vectorization if the target does not support vectors.
2594   if (!TTI.getNumberOfRegisters(TTI.getRegisterClassForType(/*Vector*/ true)))
2595     return false;
2596 
2597   bool MadeChange = false;
2598   auto FoldInst = [this, &MadeChange](Instruction &I) {
2599     Builder.SetInsertPoint(&I);
2600     bool IsFixedVectorType = isa<FixedVectorType>(I.getType());
2601     auto Opcode = I.getOpcode();
2602 
2603     // These folds should be beneficial regardless of when this pass is run
2604     // in the optimization pipeline.
2605     // The type checking is for run-time efficiency. We can avoid wasting time
2606     // dispatching to folding functions if there's no chance of matching.
2607     if (IsFixedVectorType) {
2608       switch (Opcode) {
2609       case Instruction::InsertElement:
2610         MadeChange |= vectorizeLoadInsert(I);
2611         break;
2612       case Instruction::ShuffleVector:
2613         MadeChange |= widenSubvectorLoad(I);
2614         break;
2615       default:
2616         break;
2617       }
2618     }
2619 
2620     // This transform works with scalable and fixed vectors
2621     // TODO: Identify and allow other scalable transforms
2622     if (isa<VectorType>(I.getType())) {
2623       MadeChange |= scalarizeBinopOrCmp(I);
2624       MadeChange |= scalarizeLoadExtract(I);
2625       MadeChange |= scalarizeVPIntrinsic(I);
2626     }
2627 
2628     if (Opcode == Instruction::Store)
2629       MadeChange |= foldSingleElementStore(I);
2630 
2631     // If this is an early pipeline invocation of this pass, we are done.
2632     if (TryEarlyFoldsOnly)
2633       return;
2634 
2635     // Otherwise, try folds that improve codegen but may interfere with
2636     // early IR canonicalizations.
2637     // The type checking is for run-time efficiency. We can avoid wasting time
2638     // dispatching to folding functions if there's no chance of matching.
2639     if (IsFixedVectorType) {
2640       switch (Opcode) {
2641       case Instruction::InsertElement:
2642         MadeChange |= foldInsExtFNeg(I);
2643         break;
2644       case Instruction::ShuffleVector:
2645         MadeChange |= foldShuffleOfBinops(I);
2646         MadeChange |= foldShuffleOfCastops(I);
2647         MadeChange |= foldShuffleOfShuffles(I);
2648         MadeChange |= foldSelectShuffle(I);
2649         MadeChange |= foldShuffleToIdentity(I);
2650         break;
2651       case Instruction::BitCast:
2652         MadeChange |= foldBitcastShuffle(I);
2653         break;
2654       default:
2655         MadeChange |= shrinkType(I);
2656         break;
2657       }
2658     } else {
2659       switch (Opcode) {
2660       case Instruction::Call:
2661         MadeChange |= foldShuffleFromReductions(I);
2662         MadeChange |= foldCastFromReductions(I);
2663         break;
2664       case Instruction::ICmp:
2665       case Instruction::FCmp:
2666         MadeChange |= foldExtractExtract(I);
2667         break;
2668       default:
2669         if (Instruction::isBinaryOp(Opcode)) {
2670           MadeChange |= foldExtractExtract(I);
2671           MadeChange |= foldExtractedCmps(I);
2672         }
2673         break;
2674       }
2675     }
2676   };
2677 
2678   for (BasicBlock &BB : F) {
2679     // Ignore unreachable basic blocks.
2680     if (!DT.isReachableFromEntry(&BB))
2681       continue;
2682     // Use early increment range so that we can erase instructions in loop.
2683     for (Instruction &I : make_early_inc_range(BB)) {
2684       if (I.isDebugOrPseudoInst())
2685         continue;
2686       FoldInst(I);
2687     }
2688   }
2689 
2690   while (!Worklist.isEmpty()) {
2691     Instruction *I = Worklist.removeOne();
2692     if (!I)
2693       continue;
2694 
2695     if (isInstructionTriviallyDead(I)) {
2696       eraseInstruction(*I);
2697       continue;
2698     }
2699 
2700     FoldInst(*I);
2701   }
2702 
2703   return MadeChange;
2704 }
